CREATE TABLE 학생 (
  학번 INT PRIMARY KEY,
  이름 VARCHAR(20) NOT NULL
);

-- 서브쿼리
SELECT 이름 FROM 사원 WHERE 부서코드 IN (SELECT 부서코드 FROM 부서 WHERE 위치='서울');
-- 조인
SELECT A.이름 FROM 사원 A JOIN 부서 B ON A.부서코드=B.부서코드 WHERE B.위치='서울';

-- ANY: 서브쿼리 결과 중 하나라도 조건을 만족
SELECT * FROM 사원 WHERE 급여 > ANY (SELECT 급여 FROM 사원 WHERE 부서='영업');
-- ALL: 서브쿼리 결과 모두 조건을 만족
SELECT * FROM 사원 WHERE 급여 > ALL (SELECT 급여 FROM 사원 WHERE 부서='영업');

-- EXISTS
SELECT * FROM 학생 A WHERE EXISTS (SELECT 1 FROM 수강 B WHERE A.학번=B.학번);
-- IN
SELECT * FROM 학생 WHERE 학번 IN (SELECT 학번 FROM 수강);

-- EXISTS
SELECT * FROM 학생 A WHERE EXISTS (SELECT 1 FROM 수강 B WHERE A.학번=B.학번);
-- IN
SELECT * FROM 학생 WHERE 학번 IN (SELECT 학번 FROM 수강);

CREATE TABLE 학생 (
  학번 INT PRIMARY KEY,
  나이 INT CHECK (나이 >= 18),
  학년 INT CHECK (학년 BETWEEN 1 AND 4)
);

CREATE TABLE 사원 (
  사번 INT PRIMARY KEY,
  이메일 VARCHAR(50) UNIQUE
);

CREATE TABLE 주문 (
  주문번호 INT PRIMARY KEY,
  주문일 DATE DEFAULT CURRENT_DATE,
  상태 VARCHAR(10) DEFAULT '접수'
);

CREATE TABLE 수강 (
  수강번호 INT PRIMARY KEY,
  학번 INT,
  FOREIGN KEY (학번) REFERENCES 학생(학번)
);

WITH 부서별급여 AS (
  SELECT 부서, AVG(급여) AS 평균 FROM 사원 GROUP BY 부서
)
SELECT * FROM 부서별급여 WHERE 평균 > 4000;
